/*! Local minimal HTMX-compatible polling helper for AI Media OS dashboard. */
(function () {
  function load(element) {
    var url = element.getAttribute("hx-get");
    if (!url) return;
    fetch(url, { headers: { "HX-Request": "true" } })
      .then(function (response) {
        if (!response.ok) throw new Error("Fragment request failed");
        return response.text();
      })
      .then(function (html) {
        if (element.getAttribute("hx-swap") === "outerHTML") {
          element.outerHTML = html;
        } else {
          element.innerHTML = html;
        }
      })
      .catch(function () {
        element.classList.add("fragment-error");
      });
  }

  function parseInterval(trigger) {
    var match = trigger && trigger.match(/every\s+(\d+)s/);
    return match ? Number(match[1]) * 1000 : null;
  }

  function setup() {
    document.querySelectorAll("[hx-get]").forEach(function (element) {
      var trigger = element.getAttribute("hx-trigger") || "";
      if (trigger.indexOf("load") >= 0) load(element);
      var interval = parseInterval(trigger);
      if (interval) window.setInterval(function () { load(element); }, interval);
    });
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", setup);
  } else {
    setup();
  }
})();
